import React, { useEffect, useState } from "react";

function App() {
  let [przepisyBaza, setPrzepisyBaza] = useState([]);
  let [apiRecipes, setApiRecipes] = useState([]);
  let [search, setSearch] = useState("");
  let [loading, setLoading] = useState(false);

  useEffect(() => {
    fetch("http://localhost:5000/przepisy")
      .then((response) => response.json())
      .then((data) => {
        setPrzepisyBaza(data);
      })
      .catch((error) => {
        console.log(error);
      });
  }, []);

  function szukajPrzepisu() {
    if (!search.trim()) {
      return;
    }

    setLoading(true);

    fetch("http://localhost:5000/api/przepisy/szukaj/" + search)
      .then((response) => response.json())
      .then((data) => {
        setApiRecipes(data);
        setLoading(false);
      })
      .catch((error) => {
        console.log(error);
        setLoading(false);
      });
  }

  return (
    <div className="container">
      <h1>Culinary Book</h1>

      <section className="section">
        <h2>Wyszukiwarka przepisów z API</h2>

        <div className="search-box">
          <input
            type="text"
            placeholder="Wpisz nazwę przepisu, np. chicken"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <button onClick={szukajPrzepisu}>Szukaj</button>
        </div>

        {loading && <p>Ładowanie...</p>}

        <div className="grid">
          {apiRecipes.map((recipe) => (
            <div className="card" key={recipe.id}>
              <h3>{recipe.tytul}</h3>
              <p><strong>Kategoria:</strong> {recipe.kategoria}</p>

              {recipe.obrazek && (
                <img
                  src={recipe.obrazek}
                  alt={recipe.tytul}
                  className="recipe-image"
                />
              )}

              {recipe.youtube && (
                <p>
                  <a href={recipe.youtube} target="_blank" rel="noreferrer">
                    Obejrzyj na YouTube
                  </a>
                </p>
              )}

              {recipe.instrukcje && (
                <p className="opis">
                  {recipe.instrukcje.substring(0, 180)}...
                </p>
              )}
            </div>
          ))}
        </div>
      </section>

      <section className="section">
        <h2>Przepisy z bazy danych</h2>

        <div className="grid">
          {przepisyBaza.map((przepis) => (
            <div className="card" key={przepis.id}>
              <h3>{przepis.tytul}</h3>
              <p><strong>Czas:</strong> {przepis.czas_przygotowania_min} min</p>
              <p><strong>Trudność:</strong> {przepis.poziom_trudnosci}</p>
              <p><strong>Dieta:</strong> {przepis.dieta}</p>
              <p className="opis">{przepis.opis}</p>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}

export default App;
